"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";

// ===== 水果 =====
const FRUITS = [
  { emoji: "🍎", name: "苹果" },
  { emoji: "🍌", name: "香蕉" },
  { emoji: "🍇", name: "葡萄" },
  { emoji: "🍊", name: "橘子" },
];

// ===== 固定数据：🍎×4 🍌×3 🍇×5 🍊×3 = 15 =====
const FRUIT_SEQUENCE: string[] = [
  "🍎", "🍇", "🍌", "🍊", "🍇",
  "🍎", "🍇", "🍌", "🍊", "🍇",
  "🍎", "🍌", "🍊", "🍎", "🍇",
];

// 每种水果的正确数量
const ANSWERS = [4, 3, 5, 3];

// ===== "正"字 5 笔 SVG paths（viewBox 40×50）=====
const ZHENG_STROKES = [
  "M 6 8 L 34 8", // 1. 横（上）
  "M 22 8 L 22 42", // 2. 竖（中）
  "M 6 24 L 22 24", // 3. 横（中，左半）
  "M 10 8 L 10 42", // 4. 竖（左）
  "M 6 42 L 34 42", // 5. 横（下）
];

type Phase = "record" | "count" | "done";

export default function CountPage() {
  const topicId = "data";
  const nextStep = getNextStep(topicId, "count");

  const [phase, setPhase] = useState<Phase>("record");
  const [currentIdx, setCurrentIdx] = useState(-1); // -1 = 未开始
  const [completeMsg, setCompleteMsg] = useState("");

  // 阶段 2：数量输入
  const [inputs, setInputs] = useState(["", "", "", ""]);
  const [solved, setSolved] = useState([false, false, false, false]);
  const [encourageMsg, setEncourageMsg] = useState("");
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);
  const formRef = useRef<HTMLDivElement>(null);

  // 已记录的水果中，每种水果的出现次数
  const strokeCounts = FRUITS.map((_, fi) =>
    FRUIT_SEQUENCE.slice(0, currentIdx + 1).filter(
      (f) => f === FRUITS[fi].emoji
    ).length
  );

  const allRecorded = currentIdx >= FRUIT_SEQUENCE.length - 1;

  const handleNext = () => {
    if (currentIdx < FRUIT_SEQUENCE.length - 1) {
      setCurrentIdx(currentIdx + 1);
    }
  };

  const handleFinishRecord = () => {
    setPhase("count");
  };

  const handleInputSubmit = (idx: number) => {
    if (!inputs[idx]) return;
    const val = Number(inputs[idx]);
    if (val === ANSWERS[idx]) {
      const nextSolved = [...solved];
      nextSolved[idx] = true;
      setSolved(nextSolved);
      setEncourageMsg("");
      // 全部正确
      if (nextSolved.every((s) => s)) {
        setCompleteMsg(getRandomComplete());
        setTimeout(() => setPhase("done"), 600);
      }
    } else {
      triggerShake(inputRefs.current[idx]);
      setEncourageMsg(getRandomEncourage());
      const nextInputs = [...inputs];
      nextInputs[idx] = "";
      setInputs(nextInputs);
    }
  };

  // ===== 渲染"正"字 =====
  const renderZheng = (count: number) => {
    if (count === 0) {
      return <span className="text-sm text-[var(--text-muted)]">—</span>;
    }

    const fullCount = Math.floor(count / 5);
    const remainder = count % 5;
    const zhengs: React.ReactNode[] = [];

    // 完整的"正"字
    for (let i = 0; i < fullCount; i++) {
      zhengs.push(
        <svg key={`full-${i}`} viewBox="0 0 40 50" className="h-10 w-8">
          {ZHENG_STROKES.map((d, si) => (
            <path
              key={si}
              d={d}
              stroke="var(--text)"
              strokeWidth={2.5}
              strokeLinecap="round"
              fill="none"
            />
          ))}
        </svg>
      );
    }

    // 不完整的"正"字（部分笔画）
    if (remainder > 0) {
      zhengs.push(
        <svg key="partial" viewBox="0 0 40 50" className="h-10 w-8">
          {ZHENG_STROKES.slice(0, remainder).map((d, si) => (
            <path
              key={si}
              d={d}
              stroke="var(--text)"
              strokeWidth={2.5}
              strokeLinecap="round"
              fill="none"
            />
          ))}
        </svg>
      );
    }

    return <div className="flex items-center gap-1">{zhengs}</div>;
  };

  return (
    <StepShell topicId={topicId} stepId="count">
      <div className="space-y-6">
        {/* 说明卡片 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <h2 className="text-lg font-bold text-[var(--text)]">
            {phase === "record"
              ? "用\u201c正\u201d字法记录水果"
              : phase === "count"
              ? "数一数每种水果有多少"
              : "统计完成！"}
          </h2>
          <p className="mt-1 text-sm text-[var(--text-secondary)]">
            {phase === "record"
              ? "点击\u201c下一个\u201d按钮，逐个看水果，右边表格用\u201c正\u201d字记录"
              : phase === "count"
              ? "根据\u201c正\u201d字记录，填写每种水果的数量"
              : "你已经完成了分类统计！"}
          </p>
        </div>

        {/* 阶段进度指示 */}
        <div className="flex items-center justify-center gap-2">
          <div
            className={`rounded-full px-3 py-1 text-sm transition-colors ${
              phase === "record"
                ? "bg-[var(--signal-focus)] font-semibold text-[var(--text)]"
                : "bg-[var(--signal-confirmed)]/20 text-[var(--signal-confirmed)]"
            }`}
          >
            {phase !== "record" ? "✓ " : ""}正字法记录
          </div>
          <div className="h-px w-4 bg-[var(--border)]" />
          <div
            className={`rounded-full px-3 py-1 text-sm transition-colors ${
              phase === "count"
                ? "bg-[var(--signal-focus)] font-semibold text-[var(--text)]"
                : phase === "done"
                ? "bg-[var(--signal-confirmed)]/20 text-[var(--signal-confirmed)]"
                : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
            }`}
          >
            {phase === "done" ? "✓ " : ""}数量统计
          </div>
        </div>

        {/* ===== 阶段 1：正字法记录 ===== */}
        {phase === "record" && (
          <div className="space-y-4">
            {/* 水果展示区 */}
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <div className="flex flex-wrap justify-center gap-2">
                {FRUIT_SEQUENCE.map((fruit, idx) => {
                  const isCurrent = idx === currentIdx;
                  const isPast = idx < currentIdx;
                  return (
                    <div
                      key={idx}
                      className={`flex h-12 w-12 items-center justify-center rounded-lg text-2xl transition-all duration-300 ${
                        isCurrent
                          ? "scale-125 border-2 border-[var(--signal-focus)] bg-[var(--signal-focus)]/20 shadow-[var(--shadow-md)]"
                          : isPast
                          ? "opacity-30"
                          : "opacity-50"
                      }`}
                    >
                      {fruit}
                    </div>
                  );
                })}
              </div>

              {/* 当前水果大显示 */}
              {currentIdx >= 0 && currentIdx < FRUIT_SEQUENCE.length && (
                <div className="mt-4 text-center">
                  <p className="text-sm text-[var(--text-secondary)]">
                    当前水果：
                  </p>
                  <div className="mt-1 animate-bounce-soft text-6xl">
                    {FRUIT_SEQUENCE[currentIdx]}
                  </div>
                </div>
              )}

              {/* 进度 + 按钮 */}
              <div className="mt-4 flex flex-col items-center gap-3">
                <p className="text-sm text-[var(--text-secondary)]">
                  已记录{" "}
                  <span className="font-bold text-[var(--primary)]">
                    {Math.max(0, currentIdx + 1)}
                  </span>{" "}
                  / {FRUIT_SEQUENCE.length}
                </p>

                {/* 进度条 */}
                <div className="h-2.5 w-full max-w-xs overflow-hidden rounded-full bg-[var(--bg-soft)]">
                  <div
                    className="h-full rounded-full bg-[var(--accent2)] transition-all duration-300"
                    style={{
                      width: `${(Math.max(0, currentIdx + 1) / FRUIT_SEQUENCE.length) * 100}%`,
                    }}
                  />
                </div>

                {allRecorded ? (
                  <button
                    onClick={handleFinishRecord}
                    className="rounded-full bg-[var(--signal-confirmed)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    记录完成，开始统计 →
                  </button>
                ) : (
                  <button
                    onClick={handleNext}
                    className="rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  >
                    {currentIdx < 0 ? "开始记录 →" : "下一个 →"}
                  </button>
                )}
              </div>
            </div>

            {/* 正字记录表 */}
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h3 className="mb-4 text-center text-sm font-bold text-[var(--text)]">
                &ldquo;正&rdquo;字记录表
              </h3>
              <div className="space-y-3">
                {FRUITS.map((fruit, fi) => (
                  <div
                    key={fi}
                    className="flex items-center justify-between gap-4 rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-3"
                  >
                    <div className="flex min-w-[5rem] items-center gap-2">
                      <span className="text-2xl">{fruit.emoji}</span>
                      <span className="text-sm font-medium text-[var(--text)]">
                        {fruit.name}
                      </span>
                    </div>
                    <div className="flex flex-1 items-center justify-end gap-3">
                      {renderZheng(strokeCounts[fi])}
                      <span className="min-w-[2rem] text-right text-sm font-bold text-[var(--primary)]">
                        {strokeCounts[fi]} 笔
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ===== 阶段 2：数量统计 ===== */}
        {phase === "count" && (
          <div className="space-y-4">
            {/* 正字记录回顾 */}
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-4 shadow-[var(--shadow-sm)]">
              <h3 className="mb-3 text-center text-sm font-bold text-[var(--text)]">
                &ldquo;正&rdquo;字记录回顾
              </h3>
              <div className="grid grid-cols-2 gap-2 sm:grid-cols-4">
                {FRUITS.map((fruit, fi) => (
                  <div
                    key={fi}
                    className="flex flex-col items-center gap-2 rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-3"
                  >
                    <div className="flex items-center gap-1">
                      <span className="text-2xl">{fruit.emoji}</span>
                      <span className="text-xs text-[var(--text-secondary)]">
                        {fruit.name}
                      </span>
                    </div>
                    {renderZheng(ANSWERS[fi])}
                  </div>
                ))}
              </div>
            </div>

            {/* 统计表 */}
            <div
              ref={formRef}
              className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
            >
              <h3 className="mb-2 text-center text-lg font-bold text-[var(--text)]">
                填写每种水果的数量
              </h3>
              <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
                数一数&ldquo;正&rdquo;字有几笔，就填几
              </p>
              <div className="grid grid-cols-2 gap-4">
                {FRUITS.map((fruit, fi) => (
                  <div
                    key={fi}
                    className="flex flex-col items-center gap-2"
                  >
                    <div className="flex items-center gap-2">
                      <span className="text-3xl">{fruit.emoji}</span>
                      <span className="text-sm font-medium text-[var(--text)]">
                        {fruit.name}
                      </span>
                    </div>
                    <div className="flex items-center gap-2">
                      <input
                        ref={(el) => {
                          inputRefs.current[fi] = el;
                        }}
                        type="text"
                        inputMode="numeric"
                        value={inputs[fi]}
                        disabled={solved[fi]}
                        onChange={(e) => {
                          const next = [...inputs];
                          next[fi] = e.target.value.replace(/[^0-9]/g, "");
                          setInputs(next);
                        }}
                        onKeyDown={(e) =>
                          e.key === "Enter" && handleInputSubmit(fi)
                        }
                        className={`w-16 rounded-lg border-2 px-3 py-2 text-center text-2xl font-bold focus:outline-none ${
                          solved[fi]
                            ? "border-[var(--signal-success)] text-[var(--signal-success)]"
                            : "border-[var(--border)] text-[var(--text)] focus:border-[var(--primary)]"
                        }`}
                        placeholder="?"
                      />
                      <span className="text-sm text-[var(--text-secondary)]">
                        个
                      </span>
                      {solved[fi] ? (
                        <span className="text-lg text-[var(--signal-success)]">
                          ✓
                        </span>
                      ) : (
                        <button
                          onClick={() => handleInputSubmit(fi)}
                          className="rounded-lg bg-[var(--primary)] px-3 py-2 text-sm font-medium text-white transition-colors hover:bg-[var(--primary-dark)]"
                        >
                          确定
                        </button>
                      )}
                    </div>
                  </div>
                ))}
              </div>

              {/* 鼓励提示 */}
              {encourageMsg && !solved.every((s) => s) && (
                <p className="mt-4 text-center text-sm text-[var(--text-secondary)] animate-float-in">
                  💡 {encourageMsg}
                </p>
              )}

              {/* 全部正确提示 */}
              {solved.every((s) => s) && (
                <p className="mt-4 animate-float-in text-center text-lg font-bold text-[var(--signal-success)]">
                  统计完成！🎉
                </p>
              )}
            </div>
          </div>
        )}

        {/* ===== 完成卡片 ===== */}
        {phase === "done" && (
          <div className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="animate-bounce-soft text-5xl">🎉</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              苹果{ANSWERS[0]}个、香蕉{ANSWERS[1]}个、葡萄{ANSWERS[2]}个、
              橘子{ANSWERS[3]}个，一共{ANSWERS.reduce((a, b) => a + b, 0)}个。
              <br />
              &ldquo;正&rdquo;字法真方便——5 笔画一个&ldquo;正&rdquo;，
              一看就知道有多少！
            </p>

            {/* 统计结果表 */}
            <div className="mx-auto mt-4 max-w-xs">
              <div className="grid grid-cols-4 gap-2">
                {FRUITS.map((fruit, fi) => (
                  <div
                    key={fi}
                    className="rounded-[var(--radius-sm)] bg-[var(--bg-soft)] p-3 text-center"
                  >
                    <div className="text-2xl">{fruit.emoji}</div>
                    <div className="text-lg font-bold text-[var(--primary)]">
                      {ANSWERS[fi]}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {nextStep ? (
              <Link
                href={nextStep.path}
                className="mt-6 inline-block rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            ) : (
              <Link
                href={`/learn/${topicId}`}
                className="mt-6 inline-block rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
              >
                ← 回到学习路径
              </Link>
            )}
          </div>
        )}
      </div>
    </StepShell>
  );
}
